cases.prompt_content:
{
  "type": "学术期刊图形摘要（Graphical Abstract）",
  "goal": "生成一张可直接用于期刊投稿的 Graphical Abstract，要求极简、白底、工程化克制配色、几秒内可读、绝无营销海报感",
  "canvas": {
    "aspect_ratio": "2:1",
    "background": "pure white #FFFFFF",
    "outer_padding": "60px around the diagram",
    "render_quality": "vector-clean look, anti-aliased edges, sharp text, suitable for grayscale print"
  },
  "title_block": {
    "enabled": "false",
    "title": "",
    "rule": "most journals do not allow titles inside the graphical abstract; enable only when user explicitly requested a title"
  },
  "sections": [
    {
      "id": "P1",
      "role": "Problem",
      "label": "Problem",
      "summary": "long-context QA degrades when key evidence is buried in 100K+ token corpora",
      "depiction": "a minimal line-art sketch of a tall stack of document pages with one tiny highlighted line, and a question mark glyph hovering above"
    },
    {
      "id": "P2",
      "role": "Method",
      "label": "Method",
      "summary": "two-stage retrieve-then-rerank with evidence-aware decoding",
      "depiction": "a minimal schematic of a dense retriever feeding top-K chunks into a small reranker block, then into an LLM block, all line-art rectangles connected by thin arrows"
    },
    {
      "id": "P3",
      "role": "Process",
      "label": "Key Mechanism",
      "summary": "evidence-aware attention concentrates on top-ranked chunks during decoding",
      "depiction": "a small attention strip showing K candidate chunk bars; only top-ranked bars receive denser attention lines pointing to the answer span; line-art style"
    },
    {
      "id": "P4",
      "role": "Result",
      "label": "Outcome",
      "summary": "consistent gains on multi-hop and needle-in-haystack benchmarks",
      "depiction": "a minimal qualitative bar-chart sketch (no numerical tick labels) with two grouped bars per benchmark; the proposed method bars are slightly taller, drawn in line-art with a single warm tint fill"
    }
  ],
  "section_block_style": {
    "shape": "implicit columns separated by generous whitespace, NOT four heavy rectangles in a row",
    "header_text": "section label in bold sans-serif, 12-13pt, top-aligned",
    "summary_text": "single phrase, 10pt regular, max 2 lines, no period",
    "depiction_size": "around 35-50% of column height, vertically centered"
  },
  "connectors": {
    "style": "thin arrows (1.2px) with simple triangle arrowheads, dark gray #334155, between adjacent sections only",
    "rule": "no crossing, no curved decorative arcs; arrows convey 'leads to' / 'analyzed by' relationships",
    "label_arrows": "false"
  },
  "color_palette": {
    "rule": "deep blue #1E3A8A as primary, slate blue #3B82F6 as secondary, charcoal #1F2937 for line-art and text; one low-saturation amber #F59E0B accent reserved exclusively for the Outcome bars in P4",
    "must_print_grayscale_readable": true
  },
  "typography": {
    "language": "english",
    "rule": "english → Inter / Helvetica / Arial",
    "consistency": "all section headers identical size; all summaries identical size; never mix serif and sans-serif"
  },
  "constraints": {
    "must_keep": [
      "all four sections visually equal-weight, no section dominates",
      "white background, no gradient, no decorative pattern, no photographic background",
      "summaries are short phrases, never full sentences with periods",
      "the figure must look like it could appear on an Elsevier / ACS / IEEE table of contents page",
      "no fabricated numbers anywhere; the Outcome bars are qualitative shape only"
    ],
    "avoid": [
      "marketing-poster aesthetics, brand campaign aesthetics, magazine cover aesthetics",
      "3D effects, drop shadows, gradients, glossy fills, lens flare",
      "cartoon mascots, emoji, decorative icons",
      "stock-photo-style realistic backgrounds",
      "fabricated numerical tick labels, fabricated percentages",
      "saturated colors, more than 3 main colors plus 1 accent",
      "watermarks, copyright stamps, vendor logos"
    ]
  }
}

{
  "type": "方形 Graphical Abstract（ACS / Wiley 风格）",
  "goal": "生成一张严格 1:1 方形的期刊 Graphical Abstract，四象限严格等大，工程化克制配色，内容关于硅碳复合负极循环稳定性",
  "canvas": {
    "aspect_ratio": "1:1",
    "background": "pure white #FFFFFF",
    "outer_padding": "50px around the 2x2 grid",
    "inter_panel_gap": "24px horizontal and vertical, identical",
    "render_quality": "vector-clean look, anti-aliased edges, sharp text, suitable for grayscale print"
  },
  "title_block": {
    "enabled": "false",
    "title": "",
    "rule": "ACS allows titles on the article page rather than inside the graphical abstract"
  },
  "sections": [
    {
      "id": "Q1",
      "role": "Problem",
      "label": "Problem",
      "summary": "Si anodes suffer >300% volumetric expansion, leading to SEI rupture and capacity fading",
      "depiction": "top-left quadrant: a minimal cross-sectional sketch of a silicon particle before and after lithiation, the lithiated particle visibly larger with cracking lines on its SEI shell, line-art only",
      "position": "top-left"
    },
    {
      "id": "Q2",
      "role": "Method",
      "label": "Method",
      "summary": "gradient-porous Si@C composite synthesized via spray-drying + carbonization",
      "depiction": "top-right quadrant: a small schematic of a porous Si@C particle, with inner Si nanodomains, gradient mesoporous carbon shell, and a tiny inset showing spray-drying nozzle plus furnace icons connected by thin arrows",
      "position": "top-right"
    },
    {
      "id": "Q3",
      "role": "Process",
      "label": "Mechanism",
      "summary": "gradient pores accommodate expansion and stabilize a flexible SEI",
      "depiction": "bottom-left quadrant: same Si@C particle during lithiation, with arrows indicating expansion vectors absorbed into the porous shell; SEI drawn as a thin continuous outer line, no cracks; line-art style",
      "position": "bottom-left"
    },
    {
      "id": "Q4",
      "role": "Result",
      "label": "Outcome",
      "summary": "improved capacity retention and Coulombic efficiency over 200 cycles",
      "depiction": "bottom-right quadrant: a minimal qualitative line-chart sketch with two curves over 'cycle number'; baseline curve drops faster, proposed Si@C curve stays high; no numerical tick labels, qualitative only",
      "position": "bottom-right"
    }
  ],
  "section_block_style": {
    "shape": "no heavy borders; quadrants separated by whitespace and a faint cross-axis guide line",
    "header_text": "label at top-left of each quadrant, bold sans-serif 12pt",
    "summary_text": "single phrase below header, 10pt regular, max 2 lines, no period",
    "depiction_size": "around 60% of quadrant area, centered"
  },
  "connectors": {
    "style": "thin arrows (1.2px) with simple triangle arrowheads, dark gray #334155",
    "rule": "Z-shaped reading flow Q1 → Q2 → Q3 → Q4, arrows kept short and only at quadrant boundaries; no crossing arrows, no decorative arcs",
    "label_arrows": "false"
  },
  "color_palette": {
    "rule": "deep blue #1E3A8A for Si domains, slate gray #475569 for carbon shell, charcoal #1F2937 for line-art and text; one low-saturation amber #F59E0B reserved for the proposed-method curve in Q4",
    "must_print_grayscale_readable": true
  },
  "typography": {
    "language": "english",
    "rule": "Inter / Helvetica / Arial",
    "consistency": "all four quadrant labels identical size; all four summaries identical size"
  },
  "constraints": {
    "must_keep": [
      "all four quadrants strictly equal size and equal visual weight",
      "white background, no gradient, no decorative pattern, no photo-realistic textures",
      "all numbers are qualitative; no fabricated capacity values, no fabricated cycle numbers",
      "the figure must look like an ACS Energy Letters TOC graphic"
    ],
    "avoid": [
      "marketing-poster aesthetics, magazine cover aesthetics",
      "3D rendering of battery cells, glossy metallic fills, lens flare, motion blur",
      "exaggerated cracks, sparks, smoke, or dramatic lithiation visuals",
      "cartoon mascots, emoji, decorative icons",
      "fabricated numerical tick values, fabricated capacity percentages",
      "saturated colors, more than 3 main colors plus 1 accent",
      "watermarks, journal logos, lab logos"
    ]
  }
}

{
  "type": "学术机理示意图（mechanism / pathway figure）",
  "goal": "生成一张可直接放进电池材料类论文正文的机制示意图，强调硅碳负极循环过程中的体积演化与 SEI 演化路径，学术克制、工程化配色、可单色印刷可读",
  "canvas": {
    "aspect_ratio": "16:9",
    "background": "pure white #FFFFFF",
    "outer_padding": "60px around the diagram",
    "render_quality": "vector-clean look, anti-aliased edges, sharp text"
  },
  "title_caption": {
    "figure_label": "Figure 3.",
    "caption": "Proposed evolution mechanism of the Si@C anode during repeated lithiation/delithiation.",
    "position": "bottom-center, italic serif or compact sans-serif, smaller font size"
  },
  "central_object": {
    "label": "Si@C composite particle",
    "depiction": "a simplified cross-sectional sketch of a spherical Si@C particle: inner silicon nanodomains shown as small filled circles, gradient mesoporous carbon shell shown as concentric line-art, a thin continuous SEI line as the outermost boundary; line-art schematic, no 3D, no shading",
    "position": "horizontally centered, occupying roughly 30% of canvas width",
    "style": "thin line-art / engineering schematic, no 3D, no shading, no hyperreal texture"
  },
  "stages": {
    "count": "5",
    "items": [
      {
        "id": "M1",
        "name": "Lithiation",
        "summary": "Li+ insertion into Si nanodomains",
        "highlight": "none"
      },
      {
        "id": "M2",
        "name": "Volumetric Expansion",
        "summary": "particle expansion absorbed by porous C shell",
        "highlight": "none"
      },
      {
        "id": "M3",
        "name": "SEI Stress Accumulation",
        "summary": "tensile stress concentrates at SEI interface",
        "highlight": "stress concentration region"
      },
      {
        "id": "M4",
        "name": "SEI Rupture",
        "summary": "local cracks expose fresh Si surface",
        "highlight": "failure region"
      },
      {
        "id": "M5",
        "name": "SEI Reconstruction",
        "summary": "new SEI layer forms over exposed surface",
        "highlight": "none"
      }
    ]
  },
  "result_region": {
    "enabled": "true",
    "label": "Cycling Outcome",
    "items": "irreversible Li loss, increased impedance, gradual capacity fading",
    "position": "rightmost block, visually separated from stages but stylistically consistent"
  },
  "stage_block_style": {
    "shape": "rounded rectangle (corner radius ~6px) attached to the central particle by short leader lines",
    "size_per_stage": "consistent across all stages",
    "fill": "very light slate tint #F1F5F9 by default; low-saturation warm tint #FEF3C7 only for M3, low-saturation rose tint #FEE2E2 only for M4",
    "border": "1.2px solid dark gray #334155",
    "title_text": "stage name in bold sans-serif (Inter / Helvetica / Arial), 11-12pt",
    "summary_text": "single phrase, 9-10pt regular, no full sentence, no period"
  },
  "connectors": {
    "style": "thin arrows (1.2px) with simple triangle arrowheads, dark gray #334155",
    "rule": "connect stages in temporal order M1 → M2 → M3 → M4 → M5, no crossing, no decorative curves; only label arrows when carrying a named quantity",
    "feedback_loop": {
      "enabled": "true",
      "rule": "one curved dashed arrow loops back from M5 to M1, labeled 'next cycle' in italic gray"
    }
  },
  "highlight_strategy": {
    "rule": "for M3 use a subtle amber tint #FEF3C7 background; for M4 use a subtle rose tint #FEE2E2 background; NEVER use flames, smoke, glow, lens flare, or 3D heat-map effects",
    "max_highlighted_stages": 2
  },
  "constraints": {
    "must_keep": [
      "central Si@C particle visually anchors the figure; stages flow outward in stable left-to-right reading order",
      "white background, no gradient, no decorative pattern",
      "color palette ≤ 3 main colors plus the two pale highlight tints, must remain readable in grayscale print",
      "only sans-serif typography, no script or display fonts",
      "stage labels are short phrases, never full sentences",
      "the figure must look like it came from a Journal of Power Sources / Energy Storage Materials article"
    ],
    "avoid": [
      "exaggerated cracks, sparks, smoke, glow, lens flare, motion blur",
      "3D rendering of battery cells, metallic highlights, glossy fills",
      "cartoon mascots, emoji, decorative icons, hand-drawn wobble",
      "photo-realistic photography of equipment or electrodes",
      "marketing poster aesthetics, magazine cover aesthetics",
      "fabricated capacity numbers, fabricated cycle numbers, fabricated reaction equations",
      "saturated brand-style colors, neon, vivid gradients",
      "watermarks, copyright stamps, vendor logos"
    ]
  }
}

{
  "type": "三段式因果链机制图",
  "goal": "生成一张环境催化方向论文正文用机制示意图，按'初始体系 → 多阶段反应机制 → 最终产物'三段式因果链组织，学术克制、工程化配色",
  "canvas": {
    "aspect_ratio": "16:9",
    "background": "pure white #FFFFFF",
    "outer_padding": "60px around the diagram",
    "render_quality": "vector-clean look, anti-aliased edges, sharp text"
  },
  "title_caption": {
    "figure_label": "Figure 4.",
    "caption": "Proposed pathway of UV-driven photocatalytic degradation of phenolic pollutants over the TiO2/g-C3N4 heterojunction.",
    "position": "bottom-center, italic serif or compact sans-serif, smaller font size"
  },
  "central_object": {
    "label": "TiO2 / g-C3N4 photocatalyst",
    "depiction": "a simplified line-art schematic of a layered heterojunction: top thin slab labeled g-C3N4, bottom thicker slab labeled TiO2, an interface line in between; nearby a pollutant molecule glyph (phenol ring) and a UV photon arrow pointing onto the catalyst",
    "position": "centered horizontally, occupying ~25% of canvas width",
    "style": "thin line-art / engineering schematic, no 3D, no shading"
  },
  "stages": {
    "count": "4",
    "items": [
      {
        "id": "M1",
        "name": "Photoexcitation",
        "summary": "UV generates e- / h+ pairs in g-C3N4 and TiO2",
        "highlight": "none"
      },
      {
        "id": "M2",
        "name": "Charge Separation",
        "summary": "type-II band alignment drives e-/h+ to opposite layers",
        "highlight": "interfacial transfer region"
      },
      {
        "id": "M3",
        "name": "Radical Generation",
        "summary": "•OH and •O2- radicals form at the surface",
        "highlight": "reactive surface region"
      },
      {
        "id": "M4",
        "name": "Mineralization",
        "summary": "ring opening and oxidation to CO2 + H2O + inorganic ions",
        "highlight": "none"
      }
    ]
  },
  "result_region": {
    "enabled": "true",
    "label": "Final Products",
    "items": "CO2, H2O, NO3-, SO4 2- (depending on substrate)",
    "position": "rightmost band, visually separated by larger whitespace from the mechanism stages"
  },
  "stage_block_style": {
    "shape": "rounded rectangle (corner radius ~6px), arranged as a horizontal chain in the middle band",
    "size_per_stage": "consistent across all stages",
    "fill": "very light slate tint #F1F5F9 by default; low-saturation amber tint #FEF3C7 only for M2 and M3 (highlighted reactive regions)",
    "border": "1.2px solid dark gray #334155",
    "title_text": "stage name in bold sans-serif, 11-12pt",
    "summary_text": "single phrase, 9-10pt regular, no full sentence, no period"
  },
  "connectors": {
    "style": "thin arrows (1.2px) with simple triangle arrowheads, dark gray #334155",
    "rule": "left initial system → mechanism stages M1→M2→M3→M4 → right final products; arrows are straight, no crossings; one optional thin labeled arrow above M3 indicating 'O2 / H2O' input",
    "feedback_loop": {
      "enabled": "false",
      "rule": "linear causal chain, no feedback in this variant"
    }
  },
  "highlight_strategy": {
    "rule": "M2 and M3 use a pale amber tint #FEF3C7 to indicate reactive zones; NEVER use glow, sparks, vivid gradients, or lens flare",
    "max_highlighted_stages": 2
  },
  "constraints": {
    "must_keep": [
      "three visual zones: initial system (left), mechanism stages (middle), final products (right)",
      "white background, no gradient, no decorative pattern",
      "color palette ≤ 3 main colors plus pale amber highlight, must remain readable in grayscale print",
      "only sans-serif typography, identical font family across the figure",
      "stage labels are short phrases, never full sentences",
      "the figure must look like a mechanism figure in Applied Catalysis B / Water Research"
    ],
    "avoid": [
      "exaggerated UV beams, glowing molecules, sparks, lens flare",
      "3D rendering of catalyst slabs, metallic highlights, glossy fills",
      "cartoon mascots, emoji, decorative icons, hand-drawn wobble",
      "photo-realistic backgrounds, water surface photography",
      "marketing poster aesthetics, popular-science illustration aesthetics",
      "fabricated band-gap values, fabricated rate constants, fabricated reaction equations beyond the user's scope",
      "saturated brand colors, neon, vivid gradients",
      "watermarks, copyright stamps, vendor logos"
    ]
  }
}

{
  "type": "学术论文方法 Pipeline 总览图（method overview figure）",
  "goal": "生成一张可直接放进顶会论文 method 章节首页的 pipeline 总览图，要求极简、白底、几何精确、出版物级可读",
  "canvas": {
    "aspect_ratio": "16:9",
    "background": "pure white #FFFFFF or very light gray #FAFAFA",
    "outer_padding": "60px around the diagram",
    "render_quality": "vector-clean look, anti-aliased edges, sharp text"
  },
  "title_caption": {
    "figure_label": "Figure 1.",
    "caption": "Overview of our RAG-based long-context QA pipeline: retrieve → rerank → assemble → reason.",
    "position": "bottom-center, italic serif or compact sans-serif, smaller font size"
  },
  "input": {
    "label": "Corpus + User Query",
    "thumbnail": "left tile: stack of document pages with token IDs; right snippet: a short English question string",
    "position": "leftmost, vertically centered"
  },
  "stages": {
    "count": "5",
    "items": [
      {
        "id": "S1",
        "name": "Chunking & Indexing",
        "icon_or_glyph": "a grid of overlapping text windows with small hash icon on the side",
        "sub_label": "1–2K tokens, overlap 128"
      },
      {
        "id": "S2",
        "name": "Dense Retrieval",
        "icon_or_glyph": "a dense vector as an arrow from query embedding to top-K chunk dots",
        "sub_label": "E5-large + FAISS, K=20"
      },
      {
        "id": "S3",
        "name": "Cross-Encoder Rerank",
        "icon_or_glyph": "two horizontal bars (query, passage) and a small score meter",
        "sub_label": "keep top-5"
      },
      {
        "id": "S4",
        "name": "Context Assembly",
        "icon_or_glyph": "concatenated text blocks with a bracket labeled ≤ 32K",
        "sub_label": "long-window packing"
      },
      {
        "id": "S5",
        "name": "LLM Answering",
        "icon_or_glyph": "a decoder stack with an arrow to an answer string",
        "sub_label": "GPT-4o-class, cite spans"
      }
    ]
  },
  "output": {
    "label": "Answer + Citations",
    "thumbnail": "a short answer paragraph with bracketed source IDs [1][3]",
    "position": "rightmost, vertically centered"
  },
  "stage_block_style": {
    "shape": "rounded rectangle (corner radius ~6px)",
    "size_per_stage": "around 120px wide × 80px tall, all stages identical size",
    "fill": "very light tint (e.g. #F1F5F9, #ECFEFF) — at most 2 different tints used to group stages by category",
    "border": "1.2px solid dark gray #334155",
    "title_text": "stage name in bold sans-serif (Helvetica / Inter / Arial), 11-12pt, top-center inside block",
    "icon_position": "centered inside block, takes ~50% of block height",
    "sub_label_text": "sub-label in italic gray, below stage name"
  },
  "connectors": {
    "style": "thin black arrows (1.2px) with simple triangle arrowheads",
    "rule": "horizontal flow left → right; small label above arrow only when carrying intermediate data type (e.g. 'top-20 chunk IDs', 'top-5 passages')",
    "skip_connections": {
      "enabled": "false",
      "rule": "if true, draw curved arrows that arc above the main flow with dashed style, label them 'skip' / 'residual'"
    }
  },
  "extras": {
    "loss_branch": {
      "enabled": "false",
      "label": "L = L_cls + λ L_reg",
      "rule": "if enabled, draw a small dashed branch from output back to a 'Loss' box, formula in italic"
    },
    "color_legend": {
      "enabled": "false",
      "rule": "if multiple stage tints are used, add a tiny legend bottom-right explaining each color group"
    }
  },
  "constraints": {
    "must_keep": [
      "all stage blocks identical size and vertically aligned",
      "white or near-white background, no gradient, no decoration",
      "only sans-serif typography, no script / handwritten / display fonts",
      "color palette ≤ 4 colors total, must remain readable in grayscale print",
      "input thumbnail and output thumbnail same size, both have a thin border",
      "arrows must not overlap stage blocks; labels must not collide with arrows",
      "use English labels by default unless user requested otherwise",
      "the figure should look like it came directly from a CVPR / NeurIPS PDF"
    ],
    "avoid": [
      "3D effects, drop shadows, gradients, glossy fills",
      "cartoon icons, emoji, hand-drawn wobble",
      "saturated colors (no neon, no vivid)",
      "Helvetica + serif mixed in same diagram",
      "decorative background patterns / textures",
      "illustrative photo backgrounds inside stage blocks",
      "stage blocks of unequal size or unaligned baselines",
      "Chinese mixed with English labels unless explicitly bilingual"
    ]
  }
}

{
  "type": "学术论文方法 Pipeline 总览图（method overview figure）",
  "goal": "生成一张可直接放进顶会论文或 SIGGRAPH 附件的 diffusion training pipeline 总览图，白底、几何精确、可单色印刷",
  "canvas": {
    "aspect_ratio": "2:1",
    "background": "pure white #FFFFFF",
    "outer_padding": "60px around the diagram",
    "render_quality": "vector-clean look, anti-aliased edges, sharp text"
  },
  "title_caption": {
    "figure_label": "Figure 2.",
    "caption": "Training-time pipeline of our text-conditioned latent diffusion model (LDM).",
    "position": "bottom-center, smaller sans-serif"
  },
  "input": {
    "label": "Image–Text Pairs (x, c)",
    "thumbnail": "a photo patch icon plus a one-line text caption block",
    "position": "leftmost, vertically centered"
  },
  "stages": {
    "count": "4",
    "items": [
      {
        "id": "S1",
        "name": "VAE Encode",
        "icon_or_glyph": "a small encoder arrow mapping RGB tile to 4× downsampled latent grid",
        "sub_label": "f8 downsampling, z ∈ ℝ^{4×(H/8)×(W/8)}"
      },
      {
        "id": "S2",
        "name": "Noise & Timestep",
        "icon_or_glyph": "a latent tensor with random noise overlay and a clock glyph for t",
        "sub_label": "DDPM, t ~ U(0, T)"
      },
      {
        "id": "S3",
        "name": "U-Net ϵ_θ (Text-Cond.)",
        "icon_or_glyph": "U-shaped stack with a side branch for CLIP / T5 text tokens",
        "sub_label": "cross-attn, predict noise ε"
      },
      {
        "id": "S4",
        "name": "Decoder & VAE",
        "icon_or_glyph": "MSE or v-prediction loss symbol pointing from prediction to target noise, next to a tiny decoder icon",
        "sub_label": "L_simple + optional L_lpips (aux.)"
      }
    ]
  },
  "output": {
    "label": "Trained Weights θ",
    "thumbnail": "a small disk or checkpoint symbol with a '.ckpt' style label",
    "position": "rightmost, vertically centered"
  },
  "stage_block_style": {
    "shape": "rounded rectangle (corner radius ~6px)",
    "size_per_stage": "around 120px wide × 80px tall, all stages identical size",
    "fill": "very light #F1F5F9 for S1–S2, #ECFDF5 for S3, #FEF3C7 for S4 (grouping encode / denoise / loss)",
    "border": "1.2px solid #334155",
    "title_text": "stage name in bold sans-serif, 11-12pt",
    "icon_position": "centered inside block",
    "sub_label_text": "italic gray sub-labels"
  },
  "connectors": {
    "style": "thin black arrows (1.2px)",
    "rule": "left to right; optional tiny label on arrow: 'z_t' between S2 and S3",
    "skip_connections": {
      "enabled": "true",
      "rule": "dashed skip from S1 latent representation arching to S3 input side, labeled 'skip connection' / 'residual on latent' if space allows"
    }
  },
  "extras": {
