      "placeholder": "{argument name=\"input placeholder\" default=\"输入消息\"}",
      "right_icons": ["表情", "+"]
    },
    "home_indicator": "底部 home 指示条"
  },
  "style": {
    "rendering": "高保真移动端聊天界面截图，纵向比例，看起来像真实手机截屏",
    "consistency": "气泡颜色、头像位置、时间样式严格遵循平台风格"
